function minCost(costs) {
    if (!costs || costs.length === 0) return 0;

    const n = costs.length;
    const k = costs[0].length;

    for (let i = 1; i < n; i++) {
        for (let j = 0; j < k; j++) {
            let minCost = Number.MAX_VALUE;
            for (let l = 0; l < k; l++) {
                if (l === j) continue;
                minCost = Math.min(minCost, costs[i - 1][l]);
            }
            costs[i][j] += minCost;
        }
    }
    return Math.min(...costs[n - 1]);
}
