public int minCost(int[][] costs) {
    if (costs == null || costs.length == 0) return 0;

    int n = costs.length;
    int k = costs[0].length;

    for (int i = 1; i < n; i++) {
        for (int j = 0; j < k; j++) {
            int minCost = Integer.MAX_VALUE;
            for (int l = 0; l < k; l++) {
                if (l == j) continue;
                minCost = Math.min(minCost, costs[i - 1][l]);
            }
            costs[i][j] += minCost;
        }
    }
    return Arrays.stream(costs[n - 1]).min().getAsInt();
}
```


